# --- SOLUTION: Task 2 ---
def f_gauss(x, y):
    return np.exp(-(x**2 + y**2))

def df_dx_gauss(x, y):
    return -2 * x * np.exp(-(x**2 + y**2))

def df_dy_gauss(x, y):
    return -2 * y * np.exp(-(x**2 + y**2))

def num_pd(f, x, y, var, h=1e-7):
    if var == 'x':
        return (f(x+h, y) - f(x-h, y)) / (2*h)
    else:
        return (f(x, y+h) - f(x, y-h)) / (2*h)

points = [(0, 0), (1, 0), (1, 1)]

for x0, y0 in points:
    gx = df_dx_gauss(x0, y0)
    gy = df_dy_gauss(x0, y0)
    gx_num = num_pd(f_gauss, x0, y0, 'x')
    gy_num = num_pd(f_gauss, x0, y0, 'y')
    mag = np.sqrt(gx**2 + gy**2)
    print(f"At ({x0}, {y0}):")
    print(f"  ∇f = [{gx:.6f}, {gy:.6f}]  |∇f| = {mag:.6f}")
    print(f"  Numerical: [{gx_num:.6f}, {gy_num:.6f}]  ✓")
    if mag < 1e-10:
        print("  → At the peak: gradient is zero (no direction of ascent).")
    else:
        print(f"  → Gradient points toward the peak at (0,0); steepness = {mag:.4f}.")
    print()
